@dataclass
class Vector3:
    x: float = 0.0
    y: float = 0.0
    z: float = 0.0

    def distance_to(self, other: 'Vector3') -> float:
        return math.sqrt(
            (self.x - other.x) ** 2 +
            (self.y - other.y) ** 2 +
            (self.z - other.z) ** 2
        )

    def to_dict(self):
        return {"x": self.x, "y": self.y, "z": self.z}

    @staticmethod
    def from_dict(d):
        return Vector3(d.get("x", 0), d.get("y", 0), d.get("z", 0))


@dataclass
class Obstacle:
    position: Vector3
    width: float
    height: float
    depth: float
    obstacle_id: str = ""

    def to_dict(self):
        return {
            "obstacle_id": self.obstacle_id,
            "position": self.position.to_dict(),
            "width": self.width,
            "height": self.height,
            "depth": self.depth
        }

    def contains_point_2d(self, point: Vector3) -> bool:
        half_w = self.width / 2
        half_d = self.depth / 2
        return (self.position.x - half_w <= point.x <= self.position.x + half_w and
                self.position.z - half_d <= point.z <= self.position.z + half_d)


