@dataclass
class Zone:
    center: Vector3
    current_radius: float
    target_radius: float
    shrink_rate: float  # units per second
    damage_per_second: float
    phase: int = 0

    def to_dict(self):
        return {
            "center": self.center.to_dict(),
            "current_radius": self.current_radius,
            "target_radius": self.target_radius,
            "shrink_rate": self.shrink_rate,
            "damage_per_second": self.damage_per_second,
            "phase": self.phase
        }

    def is_inside(self, position: Vector3) -> bool:
        dx = position.x - self.center.x
        dz = position.z - self.center.z
        dist = math.sqrt(dx * dx + dz * dz)
        return dist <= self.current_radius


